const e=JSON.parse('{"key":"v-38a313fb","path":"/pages/99b2c78d/","title":"Java 并发之 ThreadLocal","lang":"zh-CN","frontmatter":{"title":"Java 并发之 ThreadLocal","date":"2019-12-25T22:19:09.000Z","permalink":"/pages/99b2c78d/","category":["Java","JavaCore","并发"],"tag":["Java","JavaCore","并发"],"description":"Java 并发之 ThreadLocal ThreadLocal 是一个存储线程本地副本的工具类。 要保证线程安全，不一定非要进行同步。同步只是保证共享数据争用时的正确性，如果一个方法本来就不涉及共享数据，那么自然无须同步。 Java 中的 无同步方案 有： 可重入代码 - 也叫纯代码。如果一个方法，它的 返回结果是可以预测的，即只要输入了相同的数据，就能返回相同的结果，那它就满足可重入性，当然也是线程安全的。 线程本地存储 - 使用 ThreadLocal 为共享变量在每个线程中都创建了一个本地副本，这个副本只能被当前线程访问，其他线程无法访问，那么自然是线程安全的。","head":[["meta",{"property":"og:url","content":"https://dunwu.github.io/waterdrop/waterdrop/pages/99b2c78d/"}],["meta",{"property":"og:site_name","content":"钝悟"}],["meta",{"property":"og:title","content":"Java 并发之 ThreadLocal"}],["meta",{"property":"og:description","content":"Java 并发之 ThreadLocal ThreadLocal 是一个存储线程本地副本的工具类。 要保证线程安全，不一定非要进行同步。同步只是保证共享数据争用时的正确性，如果一个方法本来就不涉及共享数据，那么自然无须同步。 Java 中的 无同步方案 有： 可重入代码 - 也叫纯代码。如果一个方法，它的 返回结果是可以预测的，即只要输入了相同的数据，就能返回相同的结果，那它就满足可重入性，当然也是线程安全的。 线程本地存储 - 使用 ThreadLocal 为共享变量在每个线程中都创建了一个本地副本，这个副本只能被当前线程访问，其他线程无法访问，那么自然是线程安全的。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-09-03T14:51:34.000Z"}],["meta",{"property":"article:author","content":"钝悟"}],["meta",{"property":"article:tag","content":"Java"}],["meta",{"property":"article:tag","content":"JavaCore"}],["meta",{"property":"article:tag","content":"并发"}],["meta",{"property":"article:published_time","content":"2019-12-25T22:19:09.000Z"}],["meta",{"property":"article:modified_time","content":"2024-09-03T14:51:34.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Java 并发之 ThreadLocal\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2019-12-25T22:19:09.000Z\\",\\"dateModified\\":\\"2024-09-03T14:51:34.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"钝悟\\",\\"url\\":\\"https://dunwu.github.io/waterdrop\\"}]}"]]},"headers":[{"level":2,"title":"ThreadLocal 的应用","slug":"threadlocal-的应用","link":"#threadlocal-的应用","children":[]},{"level":2,"title":"ThreadLocal 的原理","slug":"threadlocal-的原理","link":"#threadlocal-的原理","children":[{"level":3,"title":"存储结构","slug":"存储结构","link":"#存储结构","children":[]},{"level":3,"title":"如何解决 Hash 冲突","slug":"如何解决-hash-冲突","link":"#如何解决-hash-冲突","children":[]},{"level":3,"title":"内存泄漏问题","slug":"内存泄漏问题","link":"#内存泄漏问题","children":[]}]},{"level":2,"title":"ThreadLocal 的误区","slug":"threadlocal-的误区","link":"#threadlocal-的误区","children":[{"level":3,"title":"ThreadLocal 错误案例","slug":"threadlocal-错误案例","link":"#threadlocal-错误案例","children":[]},{"level":3,"title":"ThreadLocal 错误案例修正","slug":"threadlocal-错误案例修正","link":"#threadlocal-错误案例修正","children":[]}]},{"level":2,"title":"InheritableThreadLocal","slug":"inheritablethreadlocal","link":"#inheritablethreadlocal","children":[]}],"git":{"createdTime":1725375094000,"updatedTime":1725375094000,"contributors":[{"name":"dunwu","email":"forbreak@163.com","commits":1}]},"readingTime":{"minutes":5.94,"words":1781},"filePathRelative":"01.Java/01.JavaCore/05.并发/Java并发之ThreadLocal.md","localizedDate":"2019年12月25日","excerpt":"<h1> Java 并发之 ThreadLocal</h1>\\n<blockquote>\\n<p><strong><code>ThreadLocal</code> 是一个存储线程本地副本的工具类</strong>。</p>\\n<p>要保证线程安全，不一定非要进行同步。同步只是保证共享数据争用时的正确性，如果一个方法本来就不涉及共享数据，那么自然无须同步。</p>\\n<p>Java 中的 <strong>无同步方案</strong> 有：</p>\\n<ul>\\n<li><strong>可重入代码</strong> - 也叫纯代码。如果一个方法，它的 <strong>返回结果是可以预测的</strong>，即只要输入了相同的数据，就能返回相同的结果，那它就满足可重入性，当然也是线程安全的。</li>\\n<li><strong>线程本地存储</strong> - 使用 <strong><code>ThreadLocal</code> 为共享变量在每个线程中都创建了一个本地副本</strong>，这个副本只能被当前线程访问，其他线程无法访问，那么自然是线程安全的。</li>\\n</ul>\\n</blockquote>","autoDesc":true}');export{e as data};
